#!/usr/bin/env python3
"""
patch_v399.py — Scheduler catch-up (staleness guard, holiday-aware) + 35-day
gate_calibration fix.

Applies, with SHA256 drift checks + .bak backups + py_compile verify:
  1. services/ai_modules/gate_calibrator.py  — fix `name 'v' is not defined`
     (bucket_analysis used {**v} where v is undefined -> {**buckets[k]}).
  2. services/scheduler_catchup.py            — NEW boot-time staleness guard
     + auto-staggered catch-up (holiday-aware) + nightly fundamentals
     warm-fill cron (18:30 ET Mon-Fri).
  3. server.py                                — wire the sweep into startup.

Idempotent. Every modified file is backed up to *.bak_v399.

Run from the repo root (the dir that contains `backend/`):
    python3 patch_v399.py
Then restart the backend so startup wiring takes effect.
"""
import base64, hashlib, json, os, sys, py_compile

BLOB = {"new_file_b64": "", "new_file_sha": "d9dff12c16c679d0b5530e59403c5f753d5a0d853537e8ca741b6b0de877b2a1", "gate_old_b64": "ICAgICAgICAgICAgImJ1Y2tldF9hbmFseXNpcyI6IHsKICAgICAgICAgICAgICAgIHN0cihrKTogeyoqdiwgIndpbl9yYXRlIjogcm91bmQoYnVja2V0c1trXVsid2lucyJdIC8gYnVja2V0c1trXVsidG90YWwiXSwgMykgaWYgYnVja2V0c1trXVsidG90YWwiXSA+IDAgZWxzZSAwfQogICAgICAgICAgICAgICAgZm9yIGsgaW4gc29ydGVkX2J1Y2tldHMKICAgICAgICAgICAgfSw=", "gate_new_b64": "", "srv_old_b64": "ICAgIHRyeToKICAgICAgICBzY2hlZHVsZXJfc2VydmljZS5zdGFydCgpCiAgICAgICAgcHJpbnQoIlRyYWRpbmcgc2NoZWR1bGVyIHN0YXJ0ZWQiKQogICAgZXhjZXB0IEV4Y2VwdGlvbiBhcyBlOgogICAgICAgIHByaW50KGYiW1dBUk5dIFRyYWRpbmcgc2NoZWR1bGVyIGZhaWxlZDoge2V9Iik=", "srv_new_b64": ""}

def find_backend():
    for c in ("backend", ".", os.path.join(os.path.dirname(__file__), "backend")):
        if os.path.exists(os.path.join(c, "server.py")):
            return os.path.abspath(c)
    print("FATAL: could not locate backend/ (no server.py found).")
    sys.exit(1)

def sha(b): return hashlib.sha256(b).hexdigest()

def b64s(k): return base64.b64decode(BLOB[k]).decode()

def backup(path):
    bak = path + ".bak_v399"
    if not os.path.exists(bak):
        with open(path, "rb") as f: data = f.read()
        with open(bak, "wb") as f: f.write(data)
        print(f"    backup -> {os.path.basename(bak)}")

def patch_replace(path, old, new, label):
    if not os.path.exists(path):
        print(f"[SKIP] {label}: file not found ({path})")
        return False
    src = open(path, encoding="utf-8").read()
    print(f"[{label}] {path}")
    print(f"    sha(before) = {sha(src.encode())[:16]}")
    if new in src:
        print("    already patched — skipping.")
        return True
    n = src.count(old)
    if n == 0:
        print("    !! anchor NOT FOUND — file drifted from expected. SKIPPING (no change).")
        return False
    if n > 1:
        print(f"    !! anchor found {n}x (expected 1) — ambiguous. SKIPPING.")
        return False
    backup(path)
    src2 = src.replace(old, new, 1)
    open(path, "w", encoding="utf-8").write(src2)
    print(f"    sha(after)  = {sha(src2.encode())[:16]}  patched")
    return True

def write_new_file(path, content_b64, expect_sha, label):
    data = base64.b64decode(content_b64)
    print(f"[{label}] {path}")
    if os.path.exists(path):
        cur = open(path, "rb").read()
        if sha(cur) == expect_sha:
            print("    already present & identical — skipping.")
            return True
        print("    exists & differs — overwriting (backup kept).")
        backup(path)
    open(path, "wb").write(data)
    got = sha(open(path, "rb").read())
    ok = "OK" if got == expect_sha else "!! SHA MISMATCH"
    print(f"    sha(written) = {got[:16]}  {ok}")
    return got == expect_sha

def main():
    be = find_backend()
    print("=" * 70)
    print(f"  patch_v399  —  backend = {be}")
    print("=" * 70)

    gate = os.path.join(be, "services", "ai_modules", "gate_calibrator.py")
    cu   = os.path.join(be, "services", "scheduler_catchup.py")
    srv  = os.path.join(be, "server.py")

    r1 = patch_replace(gate, b64s("gate_old_b64"), b64s("gate_new_b64"),
                       "1/3 gate_calibrator fix")
    r2 = write_new_file(cu, BLOB["new_file_b64"], BLOB["new_file_sha"],
                        "2/3 scheduler_catchup.py")
    r3 = patch_replace(srv, b64s("srv_old_b64"), b64s("srv_new_b64"),
                       "3/3 server.py startup wiring")

    print("\n--- py_compile verify ---")
    allok = True
    for p in (gate, cu, srv):
        try:
            py_compile.compile(p, doraise=True)
            print(f"    OK  {os.path.relpath(p, be)}")
        except Exception as e:
            allok = False
            print(f"    FAIL {os.path.relpath(p, be)}: {e}")

    print("\n" + "=" * 70)
    print(f"  results: gate={r1}  catchup={r2}  server={r3}  compile={allok}")
    if allok and r1 and r2 and r3:
        print("  ALL PATCHES APPLIED. Restart the backend to activate.")
        print("     (catch-up sweep runs ~120s after startup; nightly warm-")
        print("      fundamentals cron now fires 18:30 ET Mon-Fri.)")
    else:
        print("  WARNING: one or more steps skipped/failed — review log above.")
        print("     .bak_v399 backups exist for any modified file.")
    print("=" * 70)

if __name__ == "__main__":
    main()
